import { IUiPath } from '../core/index';

/**
 * Insights Types
 * Shared types for Maestro insights analytics endpoints
 */
/**
 * Optional filters for Insights "top" endpoint queries.
 * All fields are optional — pass any combination to narrow results.
 */
interface TopQueryOptions {
    /** Filter by package identifier */
    packageId?: string;
    /** Filter by process key */
    processKey?: string;
    /** Filter by package version */
    version?: string;
}
/**
 * Common fields returned by all Insights "top" endpoints
 */
interface GetTopBaseResponse {
    /** The package identifier */
    packageId: string;
    /** The unique process key */
    processKey: string;
}
/**
 * Response for the top run count Insights endpoint
 */
interface GetTopRunCountResponse extends GetTopBaseResponse {
    /** Number of times the process was run in the given time range */
    runCount: number;
}
/**
 * Response for the top failure count Insights endpoint
 */
interface GetTopFaultedCountResponse extends GetTopBaseResponse {
    /** Number of faulted instances in the given time range */
    faultedCount: number;
}
/**
 * SDK response for top elements with failure.
 * Shared by both MaestroProcesses and Cases — no service-specific enrichment.
 */
interface ElementGetTopFailedCountResponse {
    /** BPMN element name (falls back to element ID if name is empty) */
    elementName: string;
    /** BPMN element type (e.g. ServiceTask, ReceiveTask, IntermediateCatchEvent) */
    elementType: string;
    /** The unique process key this element belongs to */
    processKey: string;
    /** Number of failed executions of this element in the given time range */
    failedCount: number;
}
/**
 * Time bucketing granularity for insights time-series queries.
 *
 * Controls how data points are grouped on the time axis.
 */
declare enum TimeInterval {
    /** Group data points by hour */
    Hour = "HOUR",
    /** Group data points by day */
    Day = "DAY",
    /** Group data points by week */
    Week = "WEEK"
}
/**
 * Options for insights time-series queries.
 */
interface TimelineOptions {
    /**
     * How to group data points on the time axis.
     * @default TimeInterval.Day
     */
    groupBy?: TimeInterval;
}
/**
 * Final instance statuses returned by the instance status timeline endpoint.
 *
 * Only includes statuses where the instance has finished execution — Completed, Faulted, or Cancelled.
 * Active statuses like Running or Paused are not included.
 */
declare enum InstanceFinalStatus {
    /** Instance completed successfully */
    Completed = "Completed",
    /** Instance encountered an error */
    Faulted = "Faulted",
    /** Instance was cancelled */
    Cancelled = "Cancelled"
}
/**
 * Instance count for a process with a given status
 * within a specific time bucket.
 */
interface InstanceStatusTimelineResponse {
    /** Start of the time bucket in local timezone (e.g. `"5/8/2026 12:00:00 AM"`) */
    startTime: string;
    /** Instance status */
    status: InstanceFinalStatus;
    /** Number of instances with this status in the time bucket */
    count: number;
}
/**
 * Response for the top duration Insights endpoint
 */
interface GetTopDurationResponse extends GetTopBaseResponse {
    /** Total execution duration in milliseconds */
    duration: number;
}
/**
 * Element count by status for a BPMN element within a process or case
 */
interface ElementStats {
    /** BPMN element identifier */
    elementId: string;
    /** Number of successful executions */
    successCount: number;
    /** Number of failed executions */
    failCount: number;
    /** Number of terminated executions */
    terminatedCount: number;
    /** Number of paused executions */
    pausedCount: number;
    /** Number of in-progress executions */
    inProgressCount: number;
    /** Minimum duration in milliseconds */
    minDurationMs: number;
    /** Maximum duration in milliseconds */
    maxDurationMs: number;
    /** Average duration in milliseconds */
    avgDurationMs: number;
    /** 50th percentile (median) duration in milliseconds */
    p50DurationMs: number;
    /** 95th percentile duration in milliseconds */
    p95DurationMs: number;
    /** 99th percentile duration in milliseconds */
    p99DurationMs: number;
}

/**
 * Maestro Process Types
 * Types and interfaces for Maestro process management
 */

/**
 * Process information with instance statistics
 */
interface RawMaestroProcessGetAllResponse {
    /** Unique key identifying the process */
    processKey: string;
    /** Package identifier */
    packageId: string;
    /** Process name */
    name: string;
    /** Folder key where process is located */
    folderKey: string;
    /** Folder name */
    folderName: string;
    /** Available package versions */
    packageVersions: string[];
    /** Total number of versions */
    versionCount: number;
    /** Process instance count - pending */
    pendingCount: number;
    /** Process instance count - running */
    runningCount: number;
    /** Process instance count - completed */
    completedCount: number;
    /** Process instance count - paused */
    pausedCount: number;
    /** Process instance count - cancelled */
    cancelledCount: number;
    /** Process instance count - faulted */
    faultedCount: number;
    /** Process instance count - retrying */
    retryingCount: number;
    /** Process instance count - resuming */
    resumingCount: number;
    /** Process instance count - pausing */
    pausingCount: number;
    /** Process instance count - canceling */
    cancelingCount: number;
}
/**
 * Response for a single entry in top processes by run count
 */
interface ProcessGetTopRunCountResponse extends GetTopRunCountResponse {
    /** Human-readable process name */
    name: string;
}
/**
 * Response for a single entry in top processes by failure count
 */
interface ProcessGetTopFaultedCountResponse extends GetTopFaultedCountResponse {
    /** Human-readable process name */
    name: string;
}
/**
 * Response for a single entry in top processes by duration
 */
interface ProcessGetTopDurationResponse extends GetTopDurationResponse {
    /** Human-readable process name */
    name: string;
}

/**
 * Process Incident Status
 */
declare enum ProcessIncidentStatus {
    Open = "Open",
    Closed = "Closed"
}
/**
 * Process Incident Type
 */
declare enum ProcessIncidentType {
    System = "System",
    User = "User",
    Deployment = "Deployment"
}
/**
 * Process Incident Severity
 */
declare enum ProcessIncidentSeverity {
    Error = "Error",
    Warning = "Warning"
}
/**
 * Process Incident Debug Mode
 */
declare enum DebugMode {
    None = "None",
    Default = "Default",
    StepByStep = "StepByStep",
    SingleStep = "SingleStep"
}
/**
 * Process Incident Get Response
 */
interface ProcessIncidentGetResponse {
    instanceId: string;
    elementId: string;
    folderKey: string;
    processKey: string;
    incidentId: string;
    incidentStatus: ProcessIncidentStatus;
    incidentType: ProcessIncidentType | null;
    errorCode: string;
    errorMessage: string;
    errorTime: string;
    errorDetails: string;
    debugMode: DebugMode;
    incidentSeverity: ProcessIncidentSeverity | null;
    incidentElementActivityType: string;
    incidentElementActivityName: string;
}
/**
 * Process Incident Summary Get Response
 */
interface ProcessIncidentGetAllResponse {
    count: number;
    errorMessage: string;
    errorCode: string;
    firstOccuranceTime: string;
    processKey: string;
}

/**
 * Maestro Process Models
 * Model classes for Maestro processes
 */

/**
 * Service for managing UiPath Maestro Processes
 *
 * UiPath Maestro is a cloud-native orchestration layer that coordinates bots, AI agents, and humans for seamless, intelligent automation of complex workflows. [UiPath Maestro Guide](https://docs.uipath.com/maestro/automation-cloud/latest/user-guide/introduction-to-maestro)
 *
 * ### Usage
 *
 * Prerequisites: Initialize the SDK first - see [Getting Started](/uipath-typescript/getting-started/#import-initialize)
 *
 * ```typescript
 * import { MaestroProcesses } from '@uipath/uipath-typescript/maestro-processes';
 *
 * const maestroProcesses = new MaestroProcesses(sdk);
 * const allProcesses = await maestroProcesses.getAll();
 * ```
 */
interface MaestroProcessesServiceModel {
    /**
     * @returns Promise resolving to array of MaestroProcess objects with methods
     * {@link MaestroProcessGetAllResponse}
     * @example
     * ```typescript
     * // Get all processes
     * const allProcesses = await maestroProcesses.getAll();
     *
     * // Access process information and incidents
     * for (const process of allProcesses) {
     *   console.log(`Process: ${process.processKey}`);
     *   console.log(`Running instances: ${process.runningCount}`);
     *   console.log(`Faulted instances: ${process.faultedCount}`);
     *
     *   // Get incidents for this process
     *   const incidents = await process.getIncidents();
     *   console.log(`Incidents: ${incidents.length}`);
     * }
     * ```
     */
    getAll(): Promise<MaestroProcessGetAllResponse[]>;
    /**
     * Get incidents for a specific process
     *
     * @param processKey The key of the process to get incidents for
     * @param folderKey The folder key for authorization
     * @returns Promise resolving to array of incidents for the process
     * {@link ProcessIncidentGetResponse}
     * @example
     * ```typescript
     * // Get incidents for a specific process
     * const incidents = await maestroProcesses.getIncidents('<processKey>', '<folderKey>');
     *
     * // Access incident details
     * for (const incident of incidents) {
     *   console.log(`Element: ${incident.incidentElementActivityName} (${incident.incidentElementActivityType})`);
     *   console.log(`Status: ${incident.incidentStatus}`);
     *   console.log(`Error: ${incident.errorMessage}`);
     * }
     * ```
     */
    getIncidents(processKey: string, folderKey: string): Promise<ProcessIncidentGetResponse[]>;
    /**
     * Get the top 5 processes ranked by run count within a time range.
     *
     * Returns an array of up to 5 processes sorted by how many times they were executed,
     * useful for identifying the most active processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link ProcessGetTopRunCountResponse}
     * @example
     * ```typescript
     * import { MaestroProcesses } from '@uipath/uipath-typescript/maestro-processes';
     *
     * const maestroProcesses = new MaestroProcesses(sdk);
     *
     * // Get top processes by run count for the last 7 days
     * const topProcesses = await maestroProcesses.getTopRunCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topProcesses) {
     *   console.log(`${process.packageId}: ${process.runCount} runs`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top processes by run count for a specific package
     * const filtered = await maestroProcesses.getTopRunCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopRunCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<ProcessGetTopRunCountResponse[]>;
    /**
     * Get the top 10 processes ranked by failure count within a time range.
     *
     * Returns an array of up to 10 processes sorted by how many instances faulted,
     * useful for identifying the most error-prone processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link ProcessGetTopFaultedCountResponse}
     * @example
     * ```typescript
     * import { MaestroProcesses } from '@uipath/uipath-typescript/maestro-processes';
     *
     * const maestroProcesses = new MaestroProcesses(sdk);
     *
     * // Get top processes by faulted count for the last 7 days
     * const topFailing = await maestroProcesses.getTopFaultedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topFailing) {
     *   console.log(`${process.packageId}: ${process.faultedCount} failures`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top processes by faulted count for a specific package
     * const filtered = await maestroProcesses.getTopFaultedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopFaultedCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<ProcessGetTopFaultedCountResponse[]>;
    /**
     * Get the top 10 BPMN elements ranked by failure count within a time range.
     *
     * Returns an array of up to 10 elements sorted by how many times they failed,
     * useful for identifying the most error-prone activities in processes.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link ElementGetTopFailedCountResponse}
     * @example
     * ```typescript
     * import { MaestroProcesses } from '@uipath/uipath-typescript/maestro-processes';
     *
     * const maestroProcesses = new MaestroProcesses(sdk);
     *
     * // Get top failing elements for the last 7 days
     * const topFailing = await maestroProcesses.getTopElementFailedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const element of topFailing) {
     *   console.log(`${element.elementName} (${element.elementType}): ${element.failedCount} failures`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top failing elements for a specific process
     * const filtered = await maestroProcesses.getTopElementFailedCount(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { processKey: '<processKey>' }
     * );
     * ```
     */
    getTopElementFailedCount(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<ElementGetTopFailedCountResponse[]>;
    /**
     * Get all instances status counts aggregated by date for maestro processes.
     *
     * Returns time-grouped counts of instances grouped by status (Completed, Faulted, Cancelled),
     * useful for rendering time-series charts. Use `groupBy` to control the time bucket size
     * (hour, day, or week) — defaults to day if not provided.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional settings for time bucketing granularity
     * @returns Promise resolving to an array of {@link InstanceStatusTimelineResponse}
     *
     * @example
     * ```typescript
     * // Get daily instance status for the last 7 days
     * const now = new Date();
     * const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
     * const statuses = await maestroProcesses.getInstanceStatusTimeline(sevenDaysAgo, now);
     *
     * for (const entry of statuses) {
     *   console.log(`${entry.startTime} — ${entry.status}: ${entry.count}`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * import { TimeInterval } from '@uipath/uipath-typescript/maestro-processes';
     *
     * // Get hourly breakdown
     * const statuses = await maestroProcesses.getInstanceStatusTimeline(startTime, endTime, {
     *   groupBy: TimeInterval.Hour,
     * });
     * ```
     *
     * @example
     * ```typescript
     * // Get all-time data (from Unix epoch to now)
     * const allTime = await maestroProcesses.getInstanceStatusTimeline(new Date(0), new Date());
     * ```
     */
    getInstanceStatusTimeline(startTime: Date, endTime: Date, options?: TimelineOptions): Promise<InstanceStatusTimelineResponse[]>;
    /**
     * Get the top 5 processes ranked by total duration within a time range.
     *
     * Returns an array of up to 5 processes sorted by their total execution time,
     * useful for identifying the longest-running processes in a given period.
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param options - Optional filters (packageId, processKey, version)
     * @returns Promise resolving to an array of {@link ProcessGetTopDurationResponse}
     * @example
     * ```typescript
     * import { MaestroProcesses } from '@uipath/uipath-typescript/maestro-processes';
     *
     * const maestroProcesses = new MaestroProcesses(sdk);
     *
     * // Get top processes by duration for the last 7 days
     * const topProcesses = await maestroProcesses.getTopExecutionDuration(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date()
     * );
     *
     * for (const process of topProcesses) {
     *   console.log(`${process.packageId}: ${process.duration}ms total`);
     * }
     * ```
     *
     * @example
     * ```typescript
     * // Get top processes by duration for a specific package
     * const filtered = await maestroProcesses.getTopExecutionDuration(
     *   new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
     *   new Date(),
     *   { packageId: '<packageId>' }
     * );
     * ```
     */
    getTopExecutionDuration(startTime: Date, endTime: Date, options?: TopQueryOptions): Promise<ProcessGetTopDurationResponse[]>;
    /**
     * Get element stats for process instances
     *
     * Returns per-element execution counts (success, fail, terminated, paused, in-progress) and
     * duration percentile metrics (min, max, avg, p50, p95, p99) for BPMN elements within a process.
     *
     * @param processKey - Process key to filter by
     * @param packageId - Package identifier
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param packageVersion - Package version to filter by
     * @returns Promise resolving to an array of {@link ElementStats}
     * @example
     * ```typescript
     * // Get element metrics for a process
     * const elements = await maestroProcesses.getElementStats(
     *   '<processKey>',
     *   '<packageId>',
     *   new Date('2026-04-01'),
     *   new Date(),
     *   '1.0.1'
     * );
     *
     * // Analyze element performance
     * for (const element of elements) {
     *   console.log(`Element: ${element.elementId}`);
     *   console.log(`  Success: ${element.successCount}, Failed: ${element.failCount}`);
     *   console.log(`  Avg duration: ${element.avgDurationMs}ms, P95: ${element.p95DurationMs}ms`);
     * }
     * ```
     */
    getElementStats(processKey: string, packageId: string, startTime: Date, endTime: Date, packageVersion: string): Promise<ElementStats[]>;
}
interface ProcessMethods {
    /**
     * Gets incidents for this process
     *
     * @returns Promise resolving to array of process incidents
     */
    getIncidents(): Promise<ProcessIncidentGetResponse[]>;
    /**
     * Get element stats for this process
     *
     * @param startTime - Start of the time range to query
     * @param endTime - End of the time range to query
     * @param packageVersion - Package version to filter by
     * @returns Promise resolving to an array of {@link ElementStats}
     */
    getElementStats(startTime: Date, endTime: Date, packageVersion: string): Promise<ElementStats[]>;
}
type MaestroProcessGetAllResponse = RawMaestroProcessGetAllResponse & ProcessMethods;
/**
 * Creates an actionable process by combining API process data with operational methods.
 *
 * @param processData - The process data from API
 * @param service - The process service instance
 * @returns A process object with added methods
 */
declare function createProcessWithMethods(processData: MaestroProcessGetAllResponse, service: MaestroProcessesServiceModel): MaestroProcessGetAllResponse;

/**
 * Simplified universal pagination cursor
 * Used to fetch next/previous pages
 */
interface PaginationCursor {
    /** Opaque string containing all information needed to fetch next page */
    value: string;
}
/**
 * Discriminated union for pagination methods - ensures cursor and jumpToPage are mutually exclusive
 */
type PaginationMethodUnion = {
    cursor?: PaginationCursor;
    jumpToPage?: never;
} | {
    cursor?: never;
    jumpToPage?: number;
} | {
    cursor?: never;
    jumpToPage?: never;
};
/**
 * Pagination options. Users cannot specify both cursor and jumpToPage.
 */
type PaginationOptions = {
    /** Size of the page to fetch (items per page) */
    pageSize?: number;
} & PaginationMethodUnion;
/**
 * Paginated response containing items and navigation information
 */
interface PaginatedResponse<T> {
    /** The items in the current page */
    items: T[];
    /** Total count of items across all pages (if available) */
    totalCount?: number;
    /** Whether more pages are available */
    hasNextPage: boolean;
    /** Cursor to fetch the next page (if available) */
    nextCursor?: PaginationCursor;
    /** Cursor to fetch the previous page (if available) */
    previousCursor?: PaginationCursor;
    /** Current page number (1-based, if available) */
    currentPage?: number;
    /** Total number of pages (if available) */
    totalPages?: number;
    /** Whether this pagination type supports jumping to arbitrary pages */
    supportsPageJump: boolean;
}
/**
 * Response for non-paginated calls that includes both data and total count
 */
interface NonPaginatedResponse<T> {
    items: T[];
    totalCount?: number;
}
/**
 * Helper type for defining paginated method overloads
 * Creates a union type of all ways pagination can be triggered
 */
type HasPaginationOptions<T> = (T & {
    pageSize: number;
}) | (T & {
    cursor: PaginationCursor;
}) | (T & {
    jumpToPage: number;
});

